(window.webpackJsonp=window.webpackJsonp||[]).push([[858],{814:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val, left, right) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.left = (left===undefined ? null : left)\\n *     this.right = (right===undefined ? null : right)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">distance</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> countPairs = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root, distance</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    dfs(root)\\n    <span class=\\"hljs-keyword\\">return</span> res\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> []\\n        <span class=\\"hljs-keyword\\">if</span>(!root.left &amp;&amp; !root.right)<span class=\\"hljs-keyword\\">return</span> [<span class=\\"hljs-number\\">0</span>]\\n        <span class=\\"hljs-keyword\\">let</span> arr=[]\\n        <span class=\\"hljs-keyword\\">let</span> left=[], right=[]\\n        <span class=\\"hljs-keyword\\">if</span>(root.left){\\n            left=dfs(root.left)\\n            <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> left){\\n                <span class=\\"hljs-keyword\\">if</span>(++n&gt;distance)<span class=\\"hljs-keyword\\">continue</span>\\n                arr.push(n)\\n            }            \\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(root.right){\\n            right=dfs(root.right)\\n            <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> right){\\n                <span class=\\"hljs-keyword\\">if</span>(++n&gt;distance)<span class=\\"hljs-keyword\\">continue</span>\\n                arr.push(n)\\n            }            \\n        }\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;left.length;i++){\\n            <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;right.length;j++){\\n                <span class=\\"hljs-keyword\\">if</span>(left[i]+right[j]+<span class=\\"hljs-number\\">2</span>&lt;=distance)res++\\n            }\\n        }\\n        <span class=\\"hljs-comment\\">// console.log(root.val,arr,left,right)</span>\\n        <span class=\\"hljs-keyword\\">return</span> arr\\n    }\\n};\\n</code></pre>\\n"],"titleSlug":"number-of-good-leaf-nodes-pairs","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e8c\u53c9\u6811\u7684\u6839\u8282\u70b9 <code>root</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>distance</code> \u3002</p>\\n\\n<p>\u5982\u679c\u4e8c\u53c9\u6811\u4e2d\u4e24\u4e2a <strong>\u53f6</strong> \u8282\u70b9\u4e4b\u95f4\u7684 <strong>\u6700\u77ed\u8def\u5f84\u957f\u5ea6</strong> \u5c0f\u4e8e\u6216\u8005\u7b49\u4e8e <code>distance</code> \uff0c\u90a3\u5b83\u4eec\u5c31\u53ef\u4ee5\u6784\u6210\u4e00\u7ec4 <strong>\u597d\u53f6\u5b50\u8282\u70b9\u5bf9</strong> \u3002</p>\\n\\n<p>\u8fd4\u56de\u6811\u4e2d <strong>\u597d\u53f6\u5b50\u8282\u70b9\u5bf9\u7684\u6570\u91cf</strong> \u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p>&nbsp;</p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/26/e1.jpg\\" style=\\"height: 321px; width: 321px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,null,4], distance = 3\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u6811\u7684\u53f6\u8282\u70b9\u662f 3 \u548c 4 \uff0c\u5b83\u4eec\u4e4b\u95f4\u7684\u6700\u77ed\u8def\u5f84\u7684\u957f\u5ea6\u662f 3 \u3002\u8fd9\u662f\u552f\u4e00\u7684\u597d\u53f6\u5b50\u8282\u70b9\u5bf9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/26/e2.jpg\\" style=\\"height: 321px; width: 441px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,4,5,6,7], distance = 3\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\u597d\u53f6\u5b50\u8282\u70b9\u5bf9\u4e3a [4,5] \u548c [6,7] \uff0c\u6700\u77ed\u8def\u5f84\u957f\u5ea6\u90fd\u662f 2 \u3002\u4f46\u662f\u53f6\u5b50\u8282\u70b9\u5bf9 [4,6] \u4e0d\u6ee1\u8db3\u8981\u6c42\uff0c\u56e0\u4e3a\u5b83\u4eec\u4e4b\u95f4\u7684\u6700\u77ed\u8def\u5f84\u957f\u5ea6\u4e3a 4 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [7,1,4,6,null,5,3,null,null,null,null,null,2], distance = 3\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u552f\u4e00\u7684\u597d\u53f6\u5b50\u8282\u70b9\u5bf9\u662f [2,5] \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [100], distance = 1\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [1,1,1], distance = 2\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>tree</code> \u7684\u8282\u70b9\u6570\u5728 <code>[1, 2^10]</code> \u8303\u56f4\u5185\u3002</li>\\n\\t<li>\u6bcf\u4e2a\u8282\u70b9\u7684\u503c\u90fd\u5728 <code>[1, 100]</code> \u4e4b\u95f4\u3002</li>\\n\\t<li><code>1 &lt;= distance &lt;= 10</code></li>\\n</ul>\\n","title":"1530. \u597d\u53f6\u5b50\u8282\u70b9\u5bf9\u7684\u6570\u91cf","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1530"}')}}]);